import csv,json,re
stop=set('the a an of to in by for and or will who what which whose be as its is on with from that say says said report reported identified at into over after before during this have has had it his her their about next first second third country city state group team club host held named public publicly end late early new government authorities army military strike strikes air missile missiles drone war iran us israeli israel february march 2026 2025'.split())
def toks(s):
    return [t for t in re.findall(r"[A-Za-z][A-Za-z0-9'-]+", (s or '').lower()) if len(t)>2 and t not in stop]
rows=list(csv.DictReader(open('market.csv')))
active=[r for r in rows if r['is_resolved']=='False' and r['resolution_date']<='2026-03-10']
arts=[json.loads(line) for line in open('articles/2026/02/19/articles.jsonl')]
